+        if state.writer_active {
+            state.writer_waiter = Some(cx.waker().clone());
+            drop(state);
+            Poll::Pending
+        } else {
+            state.writer_active = true;
+            drop(state);
+            Poll::Ready(())
+        }
+    })
+    .await;
+
+    SplitWritePermit {
+        shared: Arc::clone(shared),
+    }
